"""
import math
def calc_dist(x1, y1, x2, y2):
    return math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2)

def calc_center(x1, y1, x2, y2):
    return (x1 + x2) / 2, (y1 + y2) / 2

def calc_radius(x1, y1, x2, y2, x3, y3):
    c1 = calc_center(x1, y1, x2, y2)
    c2 = calc_center(x2, y2, x3, y3)
    return calc_dist(c1[0], c1[1], c2[0], c2[1]) / 2

n = int(input())
points = []
for i in range(n):
    x, y = map(int, input().split())
    points.append((x, y))

if n == 2:
    print(calc_dist(points[0][0], points[0][1], points[1][0], points[1][1]) / 2)
else:
    r = calc_radius(points[0][0], points[0][1], points[1][0], points[1][1], points[2][0], points[2][1])
    for i in range(3, n):
        r = min(r, calc_radius(points[i - 2][0], points[i - 2][1], points[i - 1][0], points[i - 1][1], points[i][0], points[i][1]))
    print(r)
